from flask import Flask, redirect, url_for, session, request
import requests
import jwt
import os
from urllib.parse import urlencode

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Configuration
CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
REDIRECT_URI = 'http://localhost:5000/callback'
AUTHORIZATION_ENDPOINT = 'https://provider.com/authorize'
TOKEN_ENDPOINT = 'https://provider.com/token'
USERINFO_ENDPOINT = 'https://provider.com/userinfo'
SCOPE = 'openid profile email'

@app.route('/')
def home():
    return 'Welcome to the OpenID Connect Flask App! <a href="/login">Login</a>'

@app.route('/login')
def login():
    params = {
        'response_type': 'code',
        'client_id': CLIENT_ID,
        'redirect_uri': REDIRECT_URI,
        'scope': SCOPE,
        'nonce': os.urandom(16).hex()
    }
    return redirect(f"{AUTHORIZATION_ENDPOINT}?{urlencode(params)}")

@app.route('/callback')
def callback():
    code = request.args.get('code')
    token_response = requests.post(TOKEN_ENDPOINT, data={
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI,
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET
    })
    
    token_data = token_response.json()
    id_token = token_data.get('id_token')
    
    if id_token:
        decoded_token = jwt.decode(id_token, options={"verify_signature": False})
        session['user'] = {
            'sub': decoded_token.get('sub'),
            'name': decoded_token.get('name'),
            'email': decoded_token.get('email')
        }
    
    return redirect(url_for('profile'))

@app.route('/profile')
def profile():
    user = session.get('user')
    if user:
        return f"Hello, {user['name']}! Your email is {user['email']}."
    return redirect(url_for('home'))

if __name__ == '__main__':
    app.run(debug=False)